@WebService(serviceName = "OrderProcessingService", 
            targetNamespace = "http://soap.ecommerce.com/",
            portName = "OrderProcessingPort")
@SOAPBinding(style = Style.DOCUMENT)
public class OrderProcessingService {
    
    private static final double TAX_RATE = 0.08;

    @WebMethod(operationName = "processOrder")
    public OrderResponse processOrder(@WebParam(name = "order") Order order) {
        try {
            if (order == null) {
                return new OrderResponse(null, "FAILED", "Order cannot be null", 0.0, 0.0, 0.0, null);
            }

            if (order.getItems() == null || order.getItems().isEmpty()) {
                return new OrderResponse(null, "FAILED", "Order must contain at least one item", 0.0, 0.0, 0.0, null);
            }

            if (order.getCustomerId() == null || order.getCustomerId().trim().isEmpty()) {
                return new OrderResponse(null, "FAILED", "Customer ID is required", 0.0, 0.0, 0.0, null);
            }

            double totalAmount = calculateTotalAmount(order);
            double taxAmount = calculateTax(totalAmount);
            double grandTotal = totalAmount + taxAmount;

            String orderId = generateOrderId();
            String orderDate = new Date().toString();

            saveOrder(orderId, order, totalAmount, taxAmount, grandTotal);

            return new OrderResponse(
                orderId,
                "SUCCESS",
                "Order processed successfully",
                Math.round(totalAmount * 100.0) / 100.0,
                Math.round(taxAmount * 100.0) / 100.0,
                Math.round(grandTotal * 100.0) / 100.0,
                orderDate
            );

        } catch (Exception e) {
            return new OrderResponse(null, "FAILED", "Error processing order: " + e.getMessage(), 0.0, 0.0, 0.0, null);
        }
    }

    @WebMethod(operationName = "getOrderStatus")
    public String getOrderStatus(@WebParam(name = "orderId") String orderId) {
        if (orderId == null || orderId.trim().isEmpty()) {
            return "INVALID: Order ID is required";
        }
        return "Order " + orderId + " is being processed";
    }

    @WebMethod(operationName = "cancelOrder")
    public boolean cancelOrder(@WebParam(name = "orderId") String orderId) {
        if (orderId == null || orderId.trim().isEmpty()) {
            return false;
        }
        System.out.println("Cancelling order: " + orderId);
        return true;
    }

    @WebMethod(operationName = "calculateOrderTotal")
    public double calculateOrderTotal(@WebParam(name = "order") Order order) {
        if (order == null || order.getItems() == null) {
            return 0.0;
        }
        double totalAmount = calculateTotalAmount(order);
        double taxAmount = calculateTax(totalAmount);
        return Math.round((totalAmount + taxAmount) * 100.0) / 100.0;
    }

    private double calculateTotalAmount(Order order) {
        double total = 0.0;
        for (OrderItem item : order.getItems()) {
            if (item.getQuantity() > 0 && item.getUnitPrice() >= 0) {
                total += item.getLineTotal();
            }
        }
        return total;
    }

    private double calculateTax(double amount) {
        return amount * TAX_RATE;
    }

    private String generateOrderId() {
        return "ORD-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase();
    }

    private void saveOrder(String orderId, Order order, double totalAmount, double taxAmount, double grandTotal) {
        System.out.println("Saving order: " + orderId);
        System.out.println("Customer: " + order.getCustomerName() + " (" + order.getCustomerId() + ")");
        System.out.println("Items: " + order.getItems().size());
        System.out.println("Total Amount: $" + totalAmount);
        System.out.println("Tax Amount: $" + taxAmount);
        System.out.println("Grand Total: $" + grandTotal);
        System.out.println("Shipping Address: " + order.getShippingAddress());
    }
}